Here's the proper approach using MAUI's `Window` lifecycle events and `Preferences`:

**In your `NotePage.xaml.cs`:**

```csharp
public partial class NotePage : ContentPage
{
    private const string DraftKey = "note_draft";

    public NotePage()
    {
        InitializeComponent();
    }

    protected override void OnAppearing()
    {
        base.OnAppearing();
        // Restore draft
        if (Preferences.ContainsKey(DraftKey))
            NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    // Hook into Window lifecycle for background/resume
    protected override void OnHandlerChanged()
    {
        base.OnHandlerChanged();

        if (Window is not null)
        {
            Window.Backgrounding += OnBackgrounding;
            Window.Resumed += OnResumed;
        }
    }

    private void OnBackgrounding(object sender, BackgroundingEventArgs e)
    {
        // Save draft when app goes to background
        Preferences.Set(DraftKey, NoteEditor.Text ?? string.Empty);
    }

    private void OnResumed(object sender, EventArgs e)
    {
        // Optionally refresh UI on resume
    }

    // Clean up to avoid leaks
    protected override void OnNavigatedFrom(NavigatedFromEventArgs args)
    {
        base.OnNavigatedFrom(args);

        if (Window is not null)
        {
            Window.Backgrounding -= OnBackgrounding;
            Window.Resumed -= OnResumed;
        }
    }
}
```

**Key points:**

- **`Window.Backgrounding`** — fires when the app is sent to the background (home button, app switch). Save here.
- **`Window.Resumed`** — fires when the app returns to the foreground.
- **`Preferences`** — simple key-value store that persists across app restarts. For larger text, use `SecureStorage` or file-based storage instead.
- **Unsubscribe** from events in `OnNavigatedFrom` to prevent memory leaks.

If you need to survive a full process kill (not just backgrounding), the `OnAppearing` restore from `Preferences` handles that since `Preferences` persists to disk.
